#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
    controller->previous_has_valid_sensor = false;
    controller->previous_temperature_c = 0;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle timeout: no valid sensor for more than 1000 ms */
    if (controller->has_valid_sensor &&
        controller->last_valid_sensor_ms != 0U &&
        input.now_ms > 0U) {
        uint32_t time_since_sensor = input.now_ms - controller->last_valid_sensor_ms;
        if (time_since_sensor > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Stale sensor data - fail safe */
            controller_set_safe_off(controller);
            output.timed_out = true;
            return output;
        }
    }

    switch (input.kind) {
    case CONTROLLER_INPUT_NONE:
        /* No new input - check for timeout already done above */
        if (!controller->has_valid_sensor && controller->last_valid_sensor_ms == 0U) {
            /* Never had a valid sensor, stay in safe off */
            break;
        }
        /* If we have valid sensor but no new input, maintain current state */
        /* Only update output based on stored state */
        break;

    case CONTROLLER_INPUT_TEMPERATURE:
        {
            int temp = input.temperature_c;
            controller->has_valid_sensor = true;
            controller->last_temperature_c = temp;
            controller->last_valid_sensor_ms = input.now_ms;

            /* On boot (no previous valid sensor), keep heater off */
            if (!controller->previous_has_valid_sensor) {
                controller_set_safe_off(controller);
                break;
            }

            /* Apply control policy based on temperature and trend */
            if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
                /* Low temperature - turn heater ON */
                controller->heater_on = true;
                controller->state = CONTROLLER_STATE_HEATING;
            } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
                /* Above upper band - turn heater OFF */
                controller_set_safe_off(controller);
            } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                /* 47 <= TEMP < 50 - hold previous safe actuator state (HOLDING) */
                controller->state = CONTROLLER_STATE_HOLDING;
                /* heater_on stays as it was before entering this band */
            } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                /* 50 <= TEMP <= 52 - check for rising temperature trend */
                if (controller->last_temperature_c > controller->previous_temperature_c) {
                    /* Temperature is rising - turn heater OFF early, but state is HOLDING */
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else {
                    /* Temperature not rising - hold previous safe actuator state (HOLDING) */
                    controller->state = CONTROLLER_STATE_HOLDING;
                    /* heater_on stays as it was before entering this band */
                }
            }
            break;
        }

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        /* Malformed input or explicit timeout - fail safe */
        controller_set_safe_off(controller);
        break;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

